  "inlineSchema": "generator client {\n  provider = \"prisma-client-js\"\n}\n\ndatasource db {\n  provider = \"mysql\"\n  url      = env(\"DATABASE_URL\")\n}\n\n/**\n * ===== Enums =====\n */\n\nenum Role {\n  ADMIN\n  STAFF\n}\n\nenum ReservationStatus {\n  AWAITING_CHECKIN\n  CHECKED_IN\n}\n\nenum GuestRole {\n  GUEST\n  HOST\n}\n\nenum ReservationType {\n  PARTICULAR\n  CONFRATERNIZACAO\n  EMPRESA\n  ANIVERSARIO\n}\n\n/**\n * 🔒 Bloqueios operacionais\n * - ReservationBlockMode: PERIOD (tarde/noite/dia todo) ou SLOTS (horários específicos)\n * - ReservationBlockPeriod: períodos possíveis\n */\nenum ReservationBlockMode {\n  PERIOD\n  SLOTS\n}\n\nenum ReservationBlockPeriod {\n  AFTERNOON\n  NIGHT\n  ALL_DAY\n}\n\n/**\n * ===== Models =====\n */\n\nmodel User {\n  id           String   @id @default(uuid())\n  name         String\n  email        String   @unique\n  passwordHash String\n  role         Role     @default(STAFF)\n  isActive     Boolean  @default(true)\n  createdAt    DateTime @default(now())\n  updatedAt    DateTime @updatedAt\n\n  @@index([email])\n  @@index([role])\n}\n\nmodel Unit {\n  id        String   @id @default(uuid()) @db.VarChar(36)\n  name      String   @db.VarChar(100)\n  slug      String   @unique @db.VarChar(100)\n  isActive  Boolean  @default(true)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  reservations Reservation[]\n  areas        Area[]\n  blocks       ReservationBlock[]\n\n  @@index([name])\n  @@index([isActive])\n}\n\nmodel Area {\n  id       String  @id @default(uuid()) @db.VarChar(36)\n  unitId   String  @db.VarChar(36)\n  unit     Unit    @relation(fields: [unitId], references: [id], onDelete: Cascade)\n  name     String  @db.VarChar(191)\n  photoUrl String?\n  isActive Boolean @default(true)\n\n  iconEmoji         String? @db.VarChar(16) // ex.: \"🍺\", \"🎸\", \"🪑\"\n  description       String? @db.Text\n  capacityAfternoon Int?\n  capacityNight     Int?\n\n  reservations Reservation[]\n  blocks       ReservationBlock[]\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([unitId, name], map: \"area_unit_name_unique\")\n  @@index([unitId, name], map: \"area_unit_name_idx\")\n  @@index([isActive])\n}\n\nmodel Reservation {\n  id              String          @id @default(uuid()) @db.VarChar(36)\n  reservationCode String?         @unique @db.VarChar(6)\n  reservationType ReservationType @default(PARTICULAR)\n  createdAt       DateTime        @default(now())\n  updatedAt       DateTime        @updatedAt\n\n  fullName String  @db.VarChar(200)\n  cpf      String? @db.VarChar(14)\n\n  people Int\n  kids   Int @default(0)\n\n  // LEGADO: nome da área livre (mantido para compat de leitura)\n  area String? @db.VarChar(64)\n\n  // Relação com Area (preferencial)\n  areaId  String? @db.VarChar(36)\n  areaRef Area?   @relation(fields: [areaId], references: [id], onDelete: SetNull, onUpdate: Cascade)\n\n  // Denormalização opcional\n  areaName String? @db.VarChar(100)\n\n  reservationDate DateTime\n  birthdayDate    DateTime?\n\n  phone String? @db.VarChar(32)\n  email String? @db.VarChar(200)\n  notes String? @db.Text\n\n  utm_source   String? @db.VarChar(64)\n  utm_medium   String? @db.VarChar(64)\n  utm_campaign String? @db.VarChar(128)\n  utm_content  String? @db.VarChar(128)\n  utm_term     String? @db.VarChar(128)\n  url          String? @db.VarChar(512)\n  ref          String? @db.VarChar(256)\n\n  // LEGADO (mantido por compatibilidade de leitura):\n  unit String? @db.VarChar(64)\n\n  // Relação com Unit (preferencial)\n  unitId  String? @db.VarChar(36)\n  unitRef Unit?   @relation(fields: [unitId], references: [id], onDelete: SetNull, onUpdate: Cascade)\n\n  source String? @db.VarChar(64)\n\n  status      ReservationStatus @default(AWAITING_CHECKIN)\n  qrToken     String            @unique @db.VarChar(64)\n  qrExpiresAt DateTime?\n  checkedInAt DateTime?\n  checkedInBy String?           @db.VarChar(64)\n\n  /// relação com convidados da reserva\n  guests Guest[]\n\n  @@index([reservationDate])\n  @@index([createdAt])\n  @@index([utm_source, utm_campaign])\n  @@index([status, reservationDate])\n  @@index([unit, createdAt])\n  @@index([status, createdAt])\n  @@index([reservationCode])\n  @@index([unitId, createdAt])\n  @@index([areaId, createdAt])\n}\n\nmodel Guest {\n  id            String      @id @default(uuid()) @db.VarChar(36)\n  reservationId String      @db.VarChar(36)\n  reservation   Reservation @relation(fields: [reservationId], references: [id], onDelete: Cascade, onUpdate: Cascade)\n\n  name  String    @db.VarChar(200)\n  email String    @db.VarChar(200)\n  role  GuestRole @default(GUEST)\n\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([reservationId, email], map: \"guest_reservation_email_unique\")\n  @@index([reservationId], map: \"guest_reservation_idx\")\n  @@index([email], map: \"guest_email_idx\")\n  @@map(\"guest\")\n}\n\n/**\n * 🔒 Bloqueio operacional de reservas por unidade/área/dia/período/horário\n * - areaId = NULL  => bloqueia a unidade inteira\n * - mode = PERIOD  => use \"period\" (AFTERNOON/NIGHT/ALL_DAY)\n * - mode = SLOTS   => use \"slots\" (Json com [\"12:00\",\"12:30\",...])\n * Observação: MySQL não tem array escalar, por isso usamos Json para slots.\n */\nmodel ReservationBlock {\n  id String @id @default(uuid()) @db.VarChar(36)\n\n  unitId String @db.VarChar(36)\n  unit   Unit   @relation(fields: [unitId], references: [id], onDelete: Cascade)\n\n  areaId String? @db.VarChar(36)\n  area   Area?   @relation(fields: [areaId], references: [id], onDelete: Cascade)\n\n  date DateTime // normalizado para 00:00:00 do dia (America/Sao_Paulo)\n\n  mode   ReservationBlockMode\n  period ReservationBlockPeriod? // requerido quando mode = PERIOD\n  slots  Json? // requerido quando mode = SLOTS; ex.: [\"12:00\",\"12:30\",\"18:00\"]\n\n  reason    String?  @db.VarChar(255)\n  createdBy String?  @db.VarChar(64)\n  createdAt DateTime @default(now())\n  updatedAt DateTime @updatedAt\n\n  @@unique([unitId, areaId, date, mode, period], map: \"uniq_block_scope\")\n  @@index([unitId, date])\n  @@index([unitId, areaId, date])\n}\n",
